def build(d):
    if isinstance(d[6], str):
        # Format: id,name,short,cat,icon,benefit,explanation,value,minAge,...,url
        return {"id":d[0],"name":d[1],"shortName":d[2],"category":d[3],"icon":d[4],
            "benefit":d[5],"benefitValue":d[7],"simpleExplanation":d[6],
            "eligibility":{"minAge":d[8],"maxAge":d[9],"maxIncome":d[10],
                "categories":d[11],"gender":d[12],
                "occupations":d[13] if isinstance(d[13],list) else "all",
                "states":d[14] if isinstance(d[14],list) else "all",
                "conditions":d[15],"excludeConditions":d[16]},
            "howToApply":["Visit the official portal or nearest CSC","Submit required documents","Application will be verified","Benefits credited to your bank account"],
            "documentsRequired":["Aadhaar Card","Bank Account Details","Income Certificate (if applicable)"],
            "officialUrl":d[17],
            "whyQualifyTemplate":"Based on your profile, you meet the eligibility criteria for this scheme."}
    else:
        # Format: id,name,short,cat,icon,benefit,value,minAge,...,url
        return {"id":d[0],"name":d[1],"shortName":d[2],"category":d[3],"icon":d[4],
            "benefit":d[5],"benefitValue":d[6],"simpleExplanation":d[5],
            "eligibility":{"minAge":d[7],"maxAge":d[8],"maxIncome":d[9],
                "categories":d[10],"gender":d[11],
                "occupations":d[12] if isinstance(d[12],list) else "all",
                "states":d[13] if isinstance(d[13],list) else "all",
                "conditions":d[14],"excludeConditions":d[15]},
            "howToApply":["Visit the official portal or nearest CSC","Submit required documents","Application will be verified","Benefits credited to your bank account"],
            "documentsRequired":["Aadhaar Card","Bank Account Details","Income Certificate (if applicable)"],
            "officialUrl":d[16],
            "whyQualifyTemplate":"Based on your profile, you meet the eligibility criteria for this scheme."}

f = os.path.join(os.path.dirname(__file__),"schemes.json")
with open(f,"r",encoding="utf-8") as fp:
    existing = json.load(fp)
ids = {s["id"] for s in existing}
added = 0
for d in schemes_data:
    if d[0] not in ids:
        existing.append(build(d))
        added += 1
with open(f,"w",encoding="utf-8") as fp:
    json.dump(existing, fp, indent=2, ensure_ascii=False)
print(f"Done! Added {added} schemes. Total: {len(existing)}")
